@Test
public void testDisableIdsFlush() {
    final JanusGraph graph = getInMemoryGraph(false, false, false, 2);
    JanusGraphVertex v1 = graph.addVertex();
    JanusGraphVertex v2 = graph.addVertex();
    Edge e = v1.addEdge("knows", v2);
    e.property("prop", "old");
    graph.tx().commit();
    assertEquals("old", graph.traversal().E().next().property("prop").value());
    assertEquals(1, (long) graph.traversal().E().count().next());
    Object id = graph.traversal().E().next().id();

    // VertexIDAssigner shouldn't assign a new id if the edge is an existing one
    e = graph.traversal().E().next();
    e.property("prop", "new");
    graph.tx().commit();
    assertEquals("new", graph.traversal().E().next().property("prop").value());
    assertEquals(1, (long) graph.traversal().E().count().next());
    assertEquals(id, graph.traversal().E().next().id());
}

1° - Refactored code:
```java
@Test
public void testDisableIdsFlush() {
    final JanusGraph graph = getInMemoryGraph(false, false, false, 2);
    JanusGraphVertex v1 = graph.addVertex();
    JanusGraphVertex v2 = graph.addVertex();
    Edge e = v1.addEdge("knows", v2);
    e.property("prop", "old");
    graph.tx().commit();
    assertEquals("old", graph.traversal().E().next().property("prop").value(), "Edge property should be 'old' after initial commit");
    assertEquals(1, (long) graph.traversal().E().count().next(), "There should be exactly one edge in the graph");
    Object id = graph.traversal().E().next().id();

    // VertexIDAssigner shouldn't assign a new id if the edge is an existing one
    e = graph.traversal().E().next();
    e.property("prop", "new");
    graph.tx().commit();
    assertEquals("new", graph.traversal().E().next().property("prop").value(), "Edge property should be updated to 'new' after second commit");
    assertEquals(1, (long) graph.traversal().E().count().next(), "There should still be exactly one edge after update");
    assertEquals(id, graph.traversal().E().next().id(), "The edge ID should remain the same after property update");
}
```

