@Test
public void testAddLogProcessor() throws BackendException, NoSuchFieldException, IllegalAccessException {
    StandardJanusGraph graph = createGraphWithMockedInternals();
    StandardLogProcessorFramework logProcessorFramework = new StandardLogProcessorFramework(graph);

    logProcessorFramework.addLogProcessor("foo-identifier")
        .addProcessor((tx, txId, changeState) -> {
            // no-op processor
        })
        .setStartTimeNow()
        .setProcessorIdentifier("bar-processor")
        .build();

    Field processorLogsField = logProcessorFramework.getClass().getDeclaredField("processorLogs");
    processorLogsField.setAccessible(true);
    Map<String, Log> processorLogs = (Map<String, Log>) processorLogsField.get(logProcessorFramework);

    assertNotNull(processorLogs, "processorLogs must not be null or empty after adding a log processor");
    assertFalse(processorLogs.isEmpty(), "processorLogs should be non-empty after adding a processor");
}

@Test
public void shouldReindexIfPropertyKeyExists() {
    final Map<String, Object> map = new HashMap<>();
    map.put(STORAGE_BACKEND.toStringWithoutRoot(), "inmemory");
    final MapConfiguration config = ConfigurationUtil.loadMapConfiguration(map);
    final StandardJanusGraph graph = new StandardJanusGraph(new GraphDatabaseConfigurationBuilder().build(new CommonsConfiguration(config)));

    final String propertyKeyName = "Created_Using_Template";
    final Class dataType = Boolean.class;
    JanusGraphManagement management = graph.openManagement();
    management.makePropertyKey(propertyKeyName).dataType(dataType).make();
    management.commit();

    // Instantiate the ConfigurationManagementGraph Singleton
    // This is purposefully done after a property key is created to ensure that a REDINDEX is initiated
    new ConfigurationManagementGraph(graph);

    management = graph.openManagement();
    final JanusGraphIndex index = management.getGraphIndex("Created_Using_Template_Index");
    final PropertyKey propertyKey = management.getPropertyKey("Created_Using_Template");
    assertNotNull(index);
    assertNotNull(propertyKey);
    assertEquals(ENABLED, index.getIndexStatus(propertyKey));
    management.commit();
}

