@Test
public void graphShouldBeRemovedFromCache() throws InterruptedException {
    final JanusGraphManager jgm = new JanusGraphManager(new Settings());
    assertNotNull(jgm, "JanusGraphManager instance should not be null");
    assertNotNull(JanusGraphManager.getInstance(), "Singleton JanusGraphManager instance should not be null");
    assertNull(jgm.getGraph("graph1"), "Graph 'graph1' should initially be absent from cache");

    final Map<String, Object> map = new HashMap<>();
