    assertEquals(3, found);

    int limit = 2;
    found = Iterators.size(tx.query().has("name", Contain.IN, Arrays.asList("vertex1", "vertex2", "vertex3", "vertex4")).limit(limit).vertices().iterator());
    assertEquals(limit, found);
}

