@Test
public void testObjectVerification() {
    serialize.registerClass(2, TClass1.class, new TClass1Serializer());
    TClass1 t1 = new TClass1(24223, 0.25f);

    DataOutput out = serialize.getDataOutput(128);
    out.writeClassAndObject(t1);
    out.writeClassAndObject(null);
    out.writeObject(t1, TClass1.class);
    out.writeObject(null, TClass1.class);

    // Test failure
    for (Object o : new Object[]{new TClass2("abc", 2), Calendar.getInstance(), Lists.newArrayList()}) {
        try {
            out.writeObjectNotNull(o);
            fail("writeObjectNotNull should have thrown an exception for unsupported object: " + o);
        } catch (Exception ignored) {
        }
    }

    ReadBuffer b = out.getStaticBuffer().asReadBuffer();
    assertEquals(t1, serialize.readClassAndObject(b), "First readClassAndObject should return the original t1 object");
    assertNull(serialize.readClassAndObject(b), "Second readClassAndObject should return null");
    assertEquals(t1, serialize.readObject(b, TClass1.class), "First readObject with explicit class should return the original t1 object");
    assertNull(serialize.readObject(b, TClass1.class), "Second readObject with explicit class should return null");

    assertFalse(b.hasRemaining(), "ReadBuffer should be empty after all reads");
}
```

