@Test
public void testMultiplicityCardinality() {
    assertEquals(Multiplicity.MULTI, Multiplicity.convert(Cardinality.LIST), "Converting Cardinality.LIST should yield Multiplicity.MULTI");
    assertEquals(Multiplicity.SIMPLE, Multiplicity.convert(Cardinality.SET), "Converting Cardinality.SET should yield Multiplicity.SIMPLE");
    assertEquals(Multiplicity.MANY2ONE, Multiplicity.convert(Cardinality.SINGLE), "Converting Cardinality.SINGLE should yield Multiplicity.MANY2ONE");

    assertEquals(Cardinality.LIST, Multiplicity.MULTI.getCardinality(), "Multiplicity.MULTI cardinality should be LIST");
    assertEquals(Cardinality.SET, Multiplicity.SIMPLE.getCardinality(), "Multiplicity.SIMPLE cardinality should be SET");
    assertEquals(Cardinality.SINGLE, Multiplicity.MANY2ONE.getCardinality(), "Multiplicity.MANY2ONE cardinality should be SINGLE");

    assertFalse(Multiplicity.MULTI.isConstrained(), "Multiplicity.MULTI should not be constrained");
    assertTrue(Multiplicity.SIMPLE.isConstrained(), "Multiplicity.SIMPLE should be constrained");
    assertTrue(Multiplicity.ONE2ONE.isConstrained(), "Multiplicity.ONE2ONE should be constrained");

    assertTrue(Multiplicity.ONE2ONE.isConstrained(Direction.BOTH), "Multiplicity.ONE2ONE should be constrained in BOTH directions");
    assertTrue(Multiplicity.SIMPLE.isConstrained(Direction.BOTH), "Multiplicity.SIMPLE should be constrained in BOTH directions");

    assertFalse(Multiplicity.MULTI.isUnique(Direction.OUT), "Multiplicity.MULTI should not be unique in OUT direction");
    assertTrue(Multiplicity.MANY2ONE.isUnique(Direction.OUT), "Multiplicity.MANY2ONE should be unique in OUT direction");
}
